+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const tocStart = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEnd = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const headingLine = /^ {0,3}(#{1,6})[ \	]+(.+?)\\s*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const start = lines.findIndex((line) => tocStart.test(line));
+    if (start === -1) return text;
+
+    let end = -1;
+    for (let index = start + 1; index < lines.length; index++) {
+      if (tocEnd.test(lines[index])) {
+        end = index;
+        break;
+      }
+    }
+
+    const headings = this.getHeadings(lines, start, end, options);
+    const toc = this.buildToc(lines[start], headings, options);
+    if (end === -1) {
+      lines.splice(start, 1, ...toc);
+    } else {
+      lines.splice(start, end - start + 1, ...toc);
+    }
+    return lines.join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStartLine: number, tocEndLine: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchors = new Map<string, number>();
+    let inYaml = lines[0]?.trim() === '---';
+    let inCode = false;
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (inYaml) {
+        if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+        continue;
+      }
+      if (/^\\s*(```|~~~)/.test(line)) {
+        inCode = !inCode;
+        continue;
+      }
+      if (inCode) continue;
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (tocEndLine !== -1 && index > tocStartLine && index < tocEndLine)) continue;
+
+      const match = line.match(headingLine);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+
+      const rawText = match[2].replace(/\\s+#+\\s*$/, '');
+      if (this.isExcluded(rawText, options.excludeHeadings)) continue;
+      const explicitId = rawText.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1];
+      const textForToc = options.useExplicitIds && explicitId ? rawText.replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '') : rawText;
+      const baseAnchor = options.useExplicitIds && explicitId ? explicitId : this.toAnchor(rawText);
+      const duplicateCount = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, duplicateCount + 1);
+      headings.push({
+        level,
+        text: options.stripFormattingInToc ? this.stripFormatting(textForToc) : textForToc,
+        anchor: duplicateCount === 0 ? baseAnchor : `${baseAnchor}-${duplicateCount}`,
+      });
+    }
+    return headings;
+  }
+
+  private buildToc(startMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const content: string[] = [];
+    if (options.title) content.push(options.title);
+    for (let index = 0; index < headings.length; index++) {
+      const heading = headings[index];
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      content.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
+    }
+
+    const result = [startMarker, ''];
+    if (content.length > 0) result.push(...content, '');
+    result.push('<!-- /toc -->', '');
+    return result;
+  }
+
+  private isExcluded(text: string, exclusions: string[]): boolean {
+    return exclusions.some((exclusion) => {
+      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+        try {
+          return new RegExp(exclusion.slice(1, -1), 'i').test(text);
+        } catch (_) {
+          return false;
+        }
+      }
+      return exclusion.toLocaleLowerCase() === text.toLocaleLowerCase();
+    });
+  }
+
+  private toAnchor(text: string): string {
+    return this.stripFormatting(text)
+        .toLocaleLowerCase()
+        .replace(/\\s+/g, '-')
+        .replace(/[^a-z0-9_-]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
