+        .replace(/(`+|\\*\\*|__|~~|\\*|_|~)/g, '')
+        .replace(/\\\\([\\\\`*{}\\[\\]()#+\\-.!_>])/g, '$1');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
+      description: 'Generates a table of contents for headings in the note',
+      before: dedent`
